<template>
    <div>
        <ul id="line-legend" class="chart-legend"></ul>
        <div class="chart-overflow">
            <div class="chart-body vertical_chart_bar h-auto f-chart-width">
                <canvas class="line-chart" height="200px"></canvas>
            </div>
        </div>
    </div>
</template>

<script>
import Chart from 'chart.js';
export default {
    name: "PerformanceGraphLine",
    props: {
        graphData: Object,
    },
    methods: {
        graphRenderMethod: function() {

            var ctx = document.querySelector(".line-chart").getContext("2d");
            var gradientFill = ctx.createLinearGradient(0, 0, 0, 230);
            gradientFill.addColorStop(0, "rgba(104, 194, 233, 0.5)");
            gradientFill.addColorStop(1, "rgba(104, 194, 233, 0)");

            var lineOptions = {
                legend: {
                    display: false
                },
                legendCallback: function(chart) {
                    return chart.legend.legendItems.map((item) => {
                        return '<li><span style="background-color:' + item.strokeStyle + '"></span>' + item.text + '</li>'
                    })
                },
                scales: {
                    yAxes: [{
                        ticks: {
                            fontColor: "#C5C7D2",
                            fontSize: 13,
                            suggestedMin: 0,
                            suggestedMax: 10000,
                            stepSize: 5000,
                            callback: function(value) {
                                return '$' + value;
                            }
                        },
                        gridLines: {
                            borderDash: [8, 4],
                            color: "#F5F5FC"
                        }
                    }],
                    xAxes: [{
                        gridLines: {
                            drawBorder: false,
                            display: false
                        },
                        ticks: {
                            fontColor: "#C5C7D2",
                            fontSize: 13
                        }
                    }]
                }
            };

            var lineData = {
                labels: this.graphData.labels,
                datasets: [{
                    label: "Purchases value",
                    lineTension: 0,
                    pointRadius: 4,
                    pointBackgroundColor: '#68C2E9',
                    pointBorderWidth: 2,
                    fill: true,
                    backgroundColor: gradientFill,
                    borderColor: '#68C2E9',
                    borderWidth: 2,
                    data: this.graphData.line,
                }]
            };

            
            var lChart = new Chart(ctx, {
                type: 'line',
                data: lineData,
                options: lineOptions
            });
            document.getElementById('line-legend').innerHTML = lChart.generateLegend();
        }
    },
	mounted() {
        this.graphRenderMethod();
	},
};
</script>