<template>
	<div id="app">
		<component :is="layout">
			<router-view></router-view>
		</component>
  	</div>
</template>

<script>

import MainLayout from "@/layouts/MainLayout.vue"
import EmptyLayout from "@/layouts/EmptyLayout.vue"

export default {
	name: "App",
	components: {
		EmptyLayout,
		MainLayout
	},
	computed: {
		layout() {
			return (this.$route.meta.layout || "empty") + "-layout"
		}
	}
}
</script>

