import Vue from 'vue'
import VueRouter from 'vue-router'
import SignUp from "@/views/SignUp"
import LogIn from "@/views/LogIn"
import PasswordRecovery from "@/views/PasswordRecovery"
import Dashboard from "@/views/Dashboard"
import Analytics from "@/views/Analytics"
import Apps from "@/views/Apps"
import FunnelSteps from "@/views/FunnelSteps"
import Funnels from "@/views/Funnels"
import Single from "@/views/Single"
import Templates from "@/views/Templates"
import AddNewFunnel from "@/views/AddNewFunnel"
import Orders from "@/views/Orders"
import FunnelSettings from "@/views/FunnelSettings"
import FunnelPlusSettings from "@/views/FunnelPlusSettings"
import Automations from "@/views/Automations"
import Customers from "@/views/Customers"

Vue.use(VueRouter)

const routes = [
	{
		path: '/',
		name: 'Dashboard',
		meta: {
			layout: "main"
		},
		component: Dashboard
	},
	{
		path: '/funnel-steps',
		name: 'FunnelSteps',
		meta: {
			layout: "main"
		},
		component: FunnelSteps
	},
	{
		path: '/funnels',
		name: 'Funnels',
		meta: {
			layout: "main"
		},
		component: Funnels
	},
	{
		path: '/analytics',
		name: 'Analytics',
		meta: {
			layout: "main"
		},
		component: Analytics
	},
	{
		path: '/apps',
		name: 'Apps',
		meta: {
			layout: "main"
		},
		component: Apps
	},
	{
		path: '/single',
		name: 'Single',
		meta: {
			layout: "main"
		},
		component: Single
	},
	{
		path: '/templates',
		name: 'Templates',
		meta: {
			layout: "main"
		},
		component: Templates
	},
	{
		path: '/add-new-funnel',
		name: 'AddNewFunnel',
		meta: {
			layout: "main"
		},
		component: AddNewFunnel
	},
	{
		path: '/orders',
		name: 'Orders',
		meta: {
			layout: "main"
		},
		component: Orders
	},
	{
		path: '/funnel-settings',
		name: 'FunnelSettings',
		meta: {
			layout: "main"
		},
		component: FunnelSettings
	},
	{
		path: '/funnel-plus-settings',
		name: 'FunnelPlusSettings',
		meta: {
			layout: "main"
		},
		component: FunnelPlusSettings
	},
	{
		path: '/automations',
		name: 'Automations',
		meta: {
			layout: "main"
		},
		component: Automations
	},
	{
		path: '/customers',
		name: 'Customers',
		meta: {
			layout: "main"
		},
		component: Customers
	},
	{
		path: '/sign-up',
		name: 'SignUp',
		meta: {
			layout: "empty"
		},
		component: SignUp
	},
	{
		path: '/log-in',
		name: 'LogIn',
		meta: {
			layout: "empty"
		},
		component: LogIn
	},
	{
		path: '/password-recovery',
		name: 'PasswordRecovery',
		meta: {
			layout: "empty"
		},
		component: PasswordRecovery
	},
]

const router = new VueRouter({
	mode: 'history',
	base: process.env.BASE_URL,
	routes
})

export default router