<template>
    <div class="main">
        <StepsMainLeft/>
        <div class="main-center funnel_steps_page">
            <MainSearch />
            <div class="main-content">
                <div class="funnel_steps_top">
                    <router-link to="/funnel-plus-settings" class="settings_btn">
                        <inline-svg :src="require('@/assets/img/settings_btn.svg')"/>
                    </router-link>
                    <div class="left_img_wrpr">
                        <img :src="funnelStepsTop.mainImg" alt="">
                    </div>
                    <div class="right">
                        <div class="funnel_tag_wrpr">
                            <div class="funnel_tag">
                                <span class="icon"><inline-svg :src="funnelStepsTop.tagImg"/></span> {{funnelStepsTop.tag}}
                            </div>
                        </div>
                        <h3>{{funnelStepsTop.title}}</h3>
                        <div class="funnel_steps_urls_wrpr">
                            <div class="funnel_steps_url_item">
                                <span class="item_title">Step URL</span>
                                <div class="links-items-group">
                                    <a href="#" class="link_item">{{funnelStepsTop.stepURL}}</a>
                                    <div class="icon icon-circle pointer">
                                        <inline-svg :src="require('@/assets/img/copy_icon_sm.svg')"/>
                                    </div>
                                    <a href="#" class="icon icon-circle pointer">
                                        <inline-svg :src="require('@/assets/img/external_link_icon.svg')"/>
                                    </a>
                                </div>   
                            </div>
                            <div class="btn-wrap inline-block">
                                <a href="#" class="btn with-icon export_orders_btn"><div class="icon"> <inline-svg :src="require('@/assets/img/pencil-edit.svg')"/></div>Edit page</a>
                            </div>
                        </div>
                    </div>
                </div>
                <div class="panel funnels-panel products_panel">
                    <div class="panel-head">
                        <h2>Products
                            <div class="info_btn">
                                <inline-svg :src="require('@/assets/img/info_icon.svg')"/>
                            </div>
                        </h2>
                        <a href="#" class="btn">Add a new product</a>
                    </div>
                    <div class="panel-body panel-body_2">
                        <div class="panel-item" :class="{'disabled' : item.disabled}" v-for="(item, index) in productsPannels" :key="index">
                            <div class="products_panel_first_cell">
                                <div class="products_panel_square_label" v-if="item.squareLabel">
                                    <img :src="item.squareLabel" alt="">
                                </div>
                                <div class="number" v-if="item.firstNumber">#{{item.firstNumber}}</div>
                            </div>
                            <div class="panel-item-cell">
                                <div @click="showSettings(item.id)" class="product_panel_link">{{item.name}}</div>
                                <span class="result-tag" v-if="item.tag">{{item.tag}}</span>
                            </div>
                            <div class="panel-item-cell">
                                <h3 class="price">${{item.price}}</h3>
                                <span class="products_panel_weeks" v-if="item.pricePeriod">{{item.pricePeriod}}</span>
                            </div>
                            <div class="panel_item_btn_wrpr">
                                <a href="" class="panel_item_btn copy_btn">
                                    <inline-svg :src="require('@/assets/img/copy_icon.svg')"/>
                                </a>
                                <a href="#" @click.prevent="deleteCurrentProduct(item.id)" class="panel_item_btn delete_btn">
                                    <inline-svg :src="require('@/assets/img/delete_icon.svg')"/>
                                </a>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <MainRight 
            addedClass="not_dashboard_page"
        />
        <div class="popup_wrpr product-settings-popup-wrap" :class="{active: getProductSettingsPopup}">
            <ProductSettingsPopup @delete="deleteCurrentProduct" :currentProduct="currentProduct" />
        </div>
        <div class="popup_wrpr automation-popup-wrap" :class="{active: getAutomationPopup}">
            <AutomationPopup />
        </div>
        <!-- <div class="popup_wrpr" :class="{active: getFunnelSettingPopup}">
            <FunnelSettingPopup />
        </div> -->
    </div>
</template>

<script>
import StepsMainLeft from "@/components/StepsMainLeft.vue"
import MainRight from "@/components/MainRight.vue";
import MainSearch from "@/components/MainSearch.vue";
import ProductSettingsPopup from "@/components/popups/ProductSettingsPopup.vue"
import AutomationPopup from "@/components/popups/automation/AutomationPopup.vue";
// import FunnelSettingPopup from "@/components/popups/FunnelSettingPopup.vue"
import {mapGetters} from "vuex"

export default {
    name: "FunnelSteps",
    components: {
        MainRight,
        StepsMainLeft,
        MainSearch,
        ProductSettingsPopup,
        AutomationPopup
        // FunnelSettingPopup
    },
    data: function() {
        return {
            currentProduct: {},
            productsPannels: [
                {
                    id: 1,
                    name: '[PROMO À - 40 %] Accès à vie LEGENDE PERSONNELLE feat Idriss Aberkane',
                    squareLabel: require('../assets/img/ob_label.svg'),
                    tag: 'One-time',
                    price: 213.45,
                    pricePeriod: '2 week(s)',
                },
                {
                    id: 2,
                    name: '[PROMO À - 40 %] Accès à vie LEGENDE PERSONNELLE feat Idriss Aberkane',
                    firstNumber: 1,
                    tag: 'One-time',
                    price: 19.70,
                },
                {
                    id: 3,
                    name: '[PROMO À - 40 %] Accès à vie LEGENDE PERSONNELLE feat Idriss Aberkane',
                    firstNumber: 2,
                    tag: 'One-time',
                    price: 129.00,
                    pricePeriod: '2 week(s)',
                    disabled: true,
                },
                {
                    id: 4,
                    name: '[PROMO À - 40 %] Accès à vie LEGENDE PERSONNELLE feat Idriss Aberkane',
                    firstNumber: 3,
                    tag: 'One-time',
                    price: 5.25,
                },
            ],
            funnelStepsTop: {
                mainImg: require('../assets/img/funnel_steps_top_img.jpg'),
                title: 'Upsellx',
                tagImg: require('@/assets/img/upsell.svg'),
                tag: 'Upsell page',
                stepURL: 'ginigo.clickfunnels.com/jjjx',
                stepVariantURL: 'ginigo.clickfunnels.com/order-16944765x'
            }
        };
    },
    computed: {
        ...mapGetters(["getProductSettingsPopup", "getAutomationPopup", "getFunnelSettingPopup"]),
        notificationsOpen() {
            return this.$store.state.notificationsOpen;
        },
    },
    methods: {
        showSettings(productId) {
            this.currentProduct = this.productsPannels.find(item => item.id === productId)
            this.$store.commit("showProductSettingsPopup")
        },
        showFunnelSettingPopup() {
            this.$store.commit("showFunnelSettingPopup")
        },
        deleteCurrentProduct(id) {
            this.productsPannels = this.productsPannels.filter(item => item.id !== id)
            this.$store.commit("closeProductSettingsPopup")
        }
    },
    mounted() {
        if(this.notificationsOpen == true) {
            this.$store.dispatch('notificationsOpenToggle');
        }
    }
}
</script>