<template>
    <div class="popup_wrpr_inner">
        <div class="popup">
            <div class="popup_header">
                <h3>Create a new automation</h3>
                <a @click="closePopup" class="close_popup_btn">
                    <inline-svg :src="require('@/assets/img/popup_close.svg')"/>
                </a>
            </div>
            <div class="automation-progress-panel">
                <div class="item-prog" :class="{deactivated: step.status === 'deactivated'}" v-for="step in steps" :key="step.id">
                    <div class="icon-status">
                        <inline-svg v-if="step.status === 'active' || step.status === 'deactivated'" :src="require('@/assets/img/circle-arrow-right.svg')"/>
                        <inline-svg v-if="step.status === 'completed'" :src="require('@/assets/img/circle-checked.svg')"/>
                    </div>
                    <div class="item-prog-text">
                        <span>{{step.name}}</span>
                        <div v-if="step.status === 'completed'" class="prog-details-label">{{step.label}}</div>
                    </div>
                </div>
            </div>
            <div class="step-items">
                <component :is="currentStep"></component>
            </div>
            <div class="bottom-btns" v-if="stepComponent !== 'SavingProgress'">
                <div class="btn brdr_btn" @click="closePopup" v-if="step === 1">Cancel</div>
                <div class="btn brdr_btn" @click="backHundler" v-else>Back</div>
                <div class="btn" @click="continueHundler" :class="{disabled: continueBtnStatus}">Continue</div>
            </div>
        </div>
    </div>
</template>
 
<script>

import Step1 from "./Step1"
import Step2 from "./Step2"
import Step3 from "./Step3"
import SavingProgress from "./SavingProgress"

export default {
    name: "AutomationPopup",
    components: {
        Step1,
        Step2,
        Step3,
        SavingProgress
    },
    data() {
        return {
            stepComponent: "Step1",
            step: 1,
            steps: [
                {
                    id: 1,
                    name: "Select a trigger",
                    label: "Order Form",
                    step: "Step1",
                    status: "active"
                },
                {
                    id: 2,
                    name: "Select an integration",
                    label: "ActiveCampaign",
                    step: "Step2",
                    status: "deactivated"
                },
                {
                    id: 3,
                    name: "What action to trigger?",
                    label: "Create an order",
                    step: "Step3",
                    status: "deactivated"
                }
            ]
        }
    },
    methods: {
        closePopup() {
            this.$store.commit("closeAutomationPopup")
        },
        continueHundler() {
            this.step = this.step + 1
            if(this.step === 4) {
                this.stepComponent = "SavingProgress"
            } else {
                this.stepComponent = `Step${this.step}`
            }
            
        },
        backHundler() {
            
        }
    },
    computed: {
        currentStep() {
            return (this.stepComponent || "Step1")
        },
        continueBtnStatus() {
            let items = this.$store.getters.getTriggerItems
            let btnStatus = true
            items.map((item) => {
                if(item.active === true) {
                    btnStatus = false 
                }
            })
            return btnStatus
            
        }
    }
}
</script>