<template>

    <div class="app_settings_popup" :class="{right_open: showRightPanel}">
        <div class="popup_left_side">
            <a href="#" class="close_popup_btn" @click.prevent="closePopup">
                <inline-svg :src="require('@/assets/img/popup_close.svg')"/>
            </a>
            <a href="#" class="right_toggle" :class="{active: showRightPanel}" @click.prevent="showRightPanel = !showRightPanel">
                <svg width="10" height="10" viewBox="0 0 10 10" fill="none" xmlns="http://www.w3.org/2000/svg">
                    <path fill-rule="evenodd" clip-rule="evenodd" d="M6.96124 8.03874L6.37208 8.6279L2.74416 4.99999L6.37208 1.37207L6.96124 1.96124L3.92249 4.99999L6.96124 8.03874Z" fill="#E4E6F1"></path>
                </svg>
            </a>
            <div class="popup_side_content">
                <h3 class="popup_title">Funnel app settings</h3>
                <div class="funnel_app_item">
                    <div class="left">
                        <div class="img_wrpr">
                            <img src="@/assets/img/app_logo_3.png" alt="">
                        </div>
                        <div class="text_content">
                            <h3>Fancy Credit Card <div class="info_btn"><inline-svg :src="require('@/assets/img/info_icon.svg')"/></div></h3>
                            <p>Fancify your Credit Card box. Optimize it for MAXIMUM conversions. Make your Credit Card Input "Idiot" Proof!</p>
                        </div>
                    </div>
                    <label class="switch_checkbox_item">
                        <input type="checkbox" v-model="settingsToggle">
                        <div class="switch_checkbox"><span></span></div>
                    </label>
                </div>
                <template v-if="settingsToggle">
                    <div class="brdr_box_w_checkbox">
                        <label class="switch_checkbox_item">
                            <input type="checkbox" checked>
                            <div class="switch_checkbox"><span></span></div>
                        </label>
                        <h3>Restrict suggestions to a country <div class="info_btn"><inline-svg :src="require('@/assets/img/info_icon.svg')"/></div></h3>
                    </div>
                    <div class="brdr_box_w_checkbox">
                        <label class="switch_checkbox_item">
                            <input type="checkbox" name="" id="" checked>
                            <div class="switch_checkbox"><span></span></div>
                        </label>
                        <div class="right">
                            <h3>Restrict suggestions to a country <div class="info_btn"><inline-svg :src="require('@/assets/img/info_icon.svg')"/></div></h3>
                            <!-- <select class="js-example-basic-multiple" name="countries[]" multiple="multiple">
                                <option>United States</option>
                                <option>Canada</option>
                                <option>Ukraine</option>
                                <option>Germany</option>
                            </select> -->
                            <Select2 v-model="selectValue" :options="selectOptions" :settings="{multiple: true, dropdownAutoWidth: true, width: '100%'}" />
                        </div>
                    </div>
                    <div class="brdr_box_w_checkbox">
                        <label class="switch_checkbox_item">
                            <input type="checkbox" name="" id="">
                            <div class="switch_checkbox"><span></span></div>
                        </label>
                        <h3>Allow browser default auto-complete <div class="info_btn"><inline-svg :src="require('@/assets/img/info_icon.svg')"/></div></h3>
                    </div>
                    <div class="brdr_box_w_checkbox">
                        <label class="switch_checkbox_item">
                            <input type="checkbox" name="" id="">
                            <div class="switch_checkbox"><span></span></div>
                        </label>
                        <div class="right">
                            <h3>Allow browser default auto-complete <div class="info_btn"><inline-svg :src="require('@/assets/img/info_icon.svg')"/></div></h3>
                            <a href="" class="tag">If unchecked PayPal orders will be tracked in Funnelish instead.</a>
                        </div>
                    </div>
                </template>
                <p class="settings-hide-msg" v-else>
                    No settings for this app (at the funnel level)...
                    You can check account wide settings...
                </p>
            </div>                   

            <div class="bottom_btns_wrpr">
                <a href="" class="btn brdr_btn">Cancel</a>
                <a href="" class="btn">Save changes</a>
            </div>
        </div>
        <div class="popup_right_side">
            <h3 class="popup_title">App preview</h3>
            <p>The app will look something like this in your funnel</p>
            <div class="custom_video_player">
                <img src="@/assets/img/video_player_overlay.jpg" alt="" class="video_player_overlay">
                <a href="" class="play_btn"><inline-svg :src="require('@/assets/img/play_icon.svg')"/></a>
            </div>
        </div>
    </div>
    
</template>

<script>
export default {
    name: "AppSettingsPopup",
    data() {
        return {
            showRightPanel: false,
            selectValue: '',
            selectOptions: ["United States", "Canada", "Ukraine", "Germany"],
            settingsToggle: true
        }
    },
    methods: {
        closePopup() {
            this.$store.commit("closeSettingsPopup")
        }
    }
}
</script>