<template>
    <div class="popup_wrpr_inner">
        <div class="popup">
            <div class="popup_header">
                <h3>Add new funnel</h3>
                <a @click="closePopup" class="close_popup_btn">
                    <inline-svg :src="require('@/assets/img/popup_close.svg')"/>
                </a>
            </div>
            <label class="form_steps_label step_1" :class="{'active': step == 2}">
                <span class="icon"></span> Select a funnel type
            </label>
            <div class="funnel_type_radio_wrpr" :class="{'active': step == 1}">
                <label class="funnel_type_radio">
                    <input type="radio" name="funnel_type_radio" id="" value="funnelish" @click="continueBtnDisabled = false">
                    <div class="funnel_type_radio_box funnel_type_radio_1">
                        <div class="funnel_type_radio_box_header">
                            <div class="funnel_type_radio_logo">
                                <img src="@/assets/img/funnel_type_radio_logo_1.svg" alt="">
                            </div>
                            <span class="orange_badge">New</span>
                        </div>
                        <p>Create a  Funnelish TM funnel, includes everything you need using our own editor..</p>
                    </div>
                </label>
                <label class="funnel_type_radio">
                    <input type="radio" name="funnel_type_radio" id="" value="click_funnels" @click="continueBtnDisabled = false">
                    <div class="funnel_type_radio_box funnel_type_radio_2">
                        <div class="funnel_type_radio_logo">
                            <img src="@/assets/img/funnel_type_radio_logo_2.svg" alt="">
                        </div>
                        <p>Connect your existing Clickfunnels Funnel to our apps...</p>
                    </div>
                </label>
            </div>
            <div class="funnel_details_step" :class="{'active': step == 2}">
                <label class="form_steps_label step_2" :class="{'active': funnelDetailsStepInput}">
                    <span class="icon"></span> Your funnel details
                </label>
                <div class="form-group">
                    <input type="text" class="control-input" placeholder="Set a funnel name" v-model="funnelDetailsStepInput">
                </div>
            </div>
            <div class="popup_btn_wrpr step_1" :class="{'active': step == 1}">
                <a @click="closePopup" class="btn brdr_btn">Cancel</a>
                <a @click="step = 2" class="btn continue_btn" :class="{'disabled':continueBtnDisabled}">Continue</a>
            </div>
            <div class="popup_btn_wrpr step_2" :class="{'active': step == 2}">
                <a class="btn brdr_btn popup_back_btn" @click="step = 1">Back</a>
                <a href="" class="btn popup_add_new_funnel_btn" :class="{'disabled': !funnelDetailsStepInput}">Add new funnel</a>
            </div>
        </div>
    </div>
</template>

<script>
export default {
    name: "AddNewFunnelPopup",
    data() {
        return {
            step: 1,
            continueBtnDisabled: true,
            funnelDetailsStepInput: ''
        }
    },
    methods: {
        closePopup() {
            this.$store.commit("closeAddNewFunnelPopup")
        }
    }
}
</script>