<template>
    <div>
        <ul id="bar-legend" class="chart-legend"></ul>
        <div class="chart-overflow">
            <div class="chart-body vertical_chart_bar h-auto f-chart-width">
                <canvas class="bar-chart" height="200px"></canvas>
            </div>
        </div>
    </div>
</template>

<script>
import Chart from 'chart.js';
export default {
    name: "PerformanceGraphBar",
    props: {
        graphData: Object,
    },
    methods: {
        graphRenderMethod: function() {

            Chart.helpers.drawRoundedTopRectangle = function(ctx, x, y, width, height, radius) {
                ctx.beginPath();
                ctx.moveTo(x + radius, y);
                // top right corner
                ctx.lineTo(x + width - radius, y);
                ctx.quadraticCurveTo(x + width, y, x + width, y + radius);
                // bottom right   corner
                ctx.lineTo(x + width, y + height);
                // bottom left corner
                ctx.lineTo(x, y + height);
                // top left   
                ctx.lineTo(x, y + radius);
                ctx.quadraticCurveTo(x, y, x + radius, y);
                ctx.closePath();
                };

            Chart.elements.RoundedTopRectangle = Chart.elements.Rectangle.extend({
                draw: function() {
                    var ctx = this._chart.ctx;
                    var vm = this._view;
                    var left, right, top, bottom, signX, signY, borderSkipped;
                    var borderWidth = vm.borderWidth;

                    if (!vm.horizontal) {
                    // bar
                    left = vm.x - vm.width / 2;
                    right = vm.x + vm.width / 2;
                    top = vm.y;
                    bottom = vm.base;
                    signX = 1;
                    signY = bottom > top? 1: -1;
                    borderSkipped = vm.borderSkipped || 'bottom';
                    } else {
                    // horizontal bar
                    left = vm.base;
                    right = vm.x;
                    top = vm.y - vm.height / 2;
                    bottom = vm.y + vm.height / 2;
                    signX = right > left? 1: -1;
                    signY = 1;
                    borderSkipped = vm.borderSkipped || 'left';
                    }

                    // Canvas doesn't allow us to stroke inside the width so we can
                    // adjust the sizes to fit if we're setting a stroke on the line
                    if (borderWidth) {
                    // borderWidth shold be less than bar width and bar height.
                    var barSize = Math.min(Math.abs(left - right), Math.abs(top - bottom));
                    borderWidth = borderWidth > barSize? barSize: borderWidth;
                    var halfStroke = borderWidth / 2;
                    // Adjust borderWidth when bar top position is near vm.base(zero).
                    var borderLeft = left + (borderSkipped !== 'left'? halfStroke * signX: 0);
                    var borderRight = right + (borderSkipped !== 'right'? -halfStroke * signX: 0);
                    var borderTop = top + (borderSkipped !== 'top'? halfStroke * signY: 0);
                    var borderBottom = bottom + (borderSkipped !== 'bottom'? -halfStroke * signY: 0);
                    // not become a vertical line?
                    if (borderLeft !== borderRight) {
                        top = borderTop;
                        bottom = borderBottom;
                    }
                    // not become a horizontal line?
                    if (borderTop !== borderBottom) {
                        left = borderLeft;
                        right = borderRight;
                    }
                    }

                    // calculate the bar width and roundess
                    var barWidth = Math.abs(left - right);
                    var roundness = this._chart.config.options.barRoundness || 1.1;
                    var radius = barWidth * roundness * 0.5;

                    // keep track of the original top of the bar
                    var prevTop = top;

                    // move the top down so there is room to draw the rounded top
                    top = prevTop + radius;
                    var barRadius = top - prevTop;

                    ctx.beginPath();
                    ctx.fillStyle = vm.backgroundColor;
                    ctx.strokeStyle = vm.borderColor;
                    ctx.lineWidth = borderWidth;

                    // draw the rounded top rectangle
                    Chart.helpers.drawRoundedTopRectangle(ctx, left, (top - barRadius + 1), barWidth, bottom - prevTop, barRadius);

                    ctx.fill();
                    if (borderWidth) {
                    ctx.stroke();
                    }

                    // restore the original top value so tooltips and scales still work
                    top = prevTop;
                },
            });

            Chart.defaults.roundedBar = Chart.helpers.clone(Chart.defaults.bar);

            Chart.controllers.roundedBar = Chart.controllers.bar.extend({
                dataElementType: Chart.elements.RoundedTopRectangle
            });

            var barOptions = {
                responsive: true,
                curvature: 1,
                animationSteps: 15,
                responsive: true,
                maintainAspectRatio: false,
                scaleShowVerticalLines: false,
                scaleShowHorizontalLines: false,
                scaleShowLabels: false,
                legendCallback: function(chart) {
                    return chart.legend.legendItems.map((item) => {
                        let bgColor
                        if (item.fillStyle === "transparent") {
                            bgColor = item.strokeStyle
                        } else {
                            bgColor = item.fillStyle
                        }
                        return '<li><span style="background-color:' + bgColor + '"></span>' + item.text + '</li>'
                    })
                },
                scales: {
                    xAxes: [{
                        barThickness : 10,
                        gridLines: {
                            color: "rgba(0, 0, 0, 0)",
                            zeroLineColor: "rgba(0, 0, 0, 0)"
                        },
                        ticks: {
                            fontColor: "#C5C7D2",
                            fontSize: 13
                        }
                    }],
                    yAxes: [{
                        gridLines: {
                            borderDash: [3, 2],
                            color: "#F5F5FC",
                            zeroLineColor: "#F5F5FC"
                        },
                        ticks: {
                            fontColor: "#C5C7D2",
                            fontSize: 13,
                            suggestedMin: 0,
                            suggestedMax: 10000,
                            stepSize: 5000,
                            callback: function(value) {
                                return '$' + value;
                            }
                        }
                    }]
                },
                legend: {
                    display: false,
                }
            };

            var barData = {
                labels: this.graphData.labels,
                datasets: [{
                    label: "Purchases",
                    backgroundColor: "#D5E5FF",
                    borderColor: "#D5E5FF",
                    data: this.graphData.left,
                    order: 2
                }, {
                    label: "Visitors",
                    backgroundColor: "#4368E0",
                    borderColor: "#4368E0",
                    data: this.graphData.right,
                    order: 3
                }, 
                {
                    label: 'Conversion rate',
                    backgroundColor: 'transparent',
                    pointBackgroundColor: '#FDCC5E',
                    pointBorderWidth: 10,
                    borderColor: '#FDCC5E',
                    borderWidth: 2,
                    data: this.graphData.line,
                    type: 'line',
                    lineTension: 0,
                    order: 1
                }
                ],
            };

            var ctx = document.querySelector(".bar-chart").getContext("2d");
            var mixedChart = new Chart(ctx, {
                type: 'roundedBar',
                data: barData,
                options: barOptions
            });
            document.getElementById('bar-legend').innerHTML = mixedChart.generateLegend();
        }
    },
	mounted() {
        this.graphRenderMethod();
	},
};
</script>