                    </div>
                    <div class="brdr_box_w_checkbox p-0 b-0">
                        <label class="switch_checkbox_item">
                            <input type="checkbox" checked>
                            <div class="switch_checkbox"><span></span></div>
                        </label>
                        <h3>Select by default</h3>
                    </div>
                    <div class="brdr_box_w_checkbox p-0 b-0 mb-24">
                        <label class="switch_checkbox_item">
                            <input type="checkbox" checked>
                            <div class="switch_checkbox"><span></span></div>
                        </label>
                        <h3>Bring Forward</h3>
                    </div>
                    <div class="form-group mb-15 with_top_block">
                        <span class="form_group_top_block">Side tag (Optional)</span>
