                            <v-swatches
                                v-model="color"
                                show-fallback
                                shapes="circles"
                                popover-x="right"
                                fallback-ok-text="Set color"
                                :swatches="swatches"
                                :wrapper-style="{width: '145px', paddingLeft: '0'}"
                                :swatch-style="{width: '25px', height: '25px', borderStyle: 'solid', borderColor: '#FFFFFF', borderWidth: '2px', marginRight: '5px', marginLeft: '5px'}"
                            ></v-swatches>
                        </div>
                        <div class="font-options">
                            <span class="label">Text Size:</span>
                            <label class="radio">
                                <input type="radio" name="font" checked="checked">
                                <span class="radiomark"></span>
                                Small
                            </label>
                            <label class="radio">
                                <input type="radio" name="font" checked="checked">
                                <span class="radiomark"></span>
                                Big
                            </label>
                        </div>
                    </div>
                    <div class="form-group mb-15 with_top_block">
                        <span class="form_group_top_block">Top tag (Optional)</span>
                        <input type="text" class="control-input">
                    </div>
                </div>
                <div class="brdr_content_wrpr">
                    <h3 class="brdr_content_title">Clickfunnels Tracking</h3>
                    <div class="txt-wrap">
                        <p>
                            <strong>This is an order bump,</strong> in order to track your order bump sales you'll have to use the tracking ID provided within each product.
                        </p>
                        <p>
                            The <strong>"Cart Product ID + Orderbump"</strong> ID can be used to create a tracking product within Clickfunnels for the order bump when combined with each product.
                        </p>
                    </div>
                </div>
                <div class="brdr_content_wrpr">
                    <h3 class="brdr_content_title">Clickfunnels Tracking</h3>
                    <div class="txt-wrap">
                        <p>
                            In order to have your sales tracked in Clickfunnels,
                            you'll have to copy the Product Cart ID below and add it to your PayPal product in Clickfunnels under <strong>"Your Funnel" > Settings > 3rd Party Membership Access.</strong>
                        </p>
                    </div>
                    <div class="form-group with-copy-icon mb-15 with_top_block">
                        <span class="form_group_top_block">Cart product ID</span>
                        <input type="text" class="control-input" value="Accès_vie_LEGENDE PERSONNELLE">
                        <div class="copy-icon"><inline-svg :src="require('@/assets/img/copy_icon_sm.svg')"/></div>
                    </div>
                    <div class="control-info mb-24">
                        Use this ID to track sales of the current product when bought alone.
                    </div>
                    <div class="form-group with-copy-icon mb-15 with_top_block">
                        <span class="form_group_top_block">Product name</span>
                        <input type="text" class="control-input" value="Accès_vie_LEGENDE PERSONNELLE">
                        <div class="copy-icon"><inline-svg :src="require('@/assets/img/copy_icon_sm.svg')"/></div>
                    </div>
                    <div class="control-info">
                        Use this ID to track sales of the current product when bought with the order bump.
                    </div>
                </div>
                <div class="brdr_content_wrpr">
                    <h3 class="brdr_content_title">Variants</h3>
                    <div class="txt-wrap">
                        <p>
                            Order bumps do not support having variants, If you believe this is something we should work on then do let us know at <a href="#">support@funnelish.com.</a>
                        </p>
                    </div>
                </div>
                <div class="brdr_content_wrpr">
                    <h3 class="brdr_content_title">Variants</h3>
                    <div class="txt-wrap">
                        <p>
                            Add variants if this product has multiple options, such as size or color.
                        </p>
                    </div>
                    <div class="variants-wrap">
                        <div class="variant-box" v-for="item in variants" :key="item.id">
                            <div class="left">
                                <div class="label with-icon">Variant <div class="icon"><inline-svg :src="require('@/assets/img/info_icon.svg')"/></div></div>
                                <div class="form-group">
                                    <input type="text" class="control-input" v-model="item.variantControl">
                                </div>
                                <div class="delete-icon" @click="deleteVariant(item.id)"><inline-svg :src="require('@/assets/img/delete_icon.svg')"/></div>
                            </div>
                            <div class="right">
                                <div class="label-top-group">
                                    <div class="label with-icon">Options <div class="icon"><inline-svg :src="require('@/assets/img/info_icon.svg')"/></div></div>
                                    <div v-if="item.options.length" class="label with-icon">Soldout</div>
                                </div>
                                <p v-if="!item.options.length" class="msg">No options yet, add an option to get started.</p>
                                <div v-else class="option-items-wrap">
                                    <div class="option-item" v-for="option in item.options" :key="option.id">
                                        <input type="text" class="control-input" v-model="option.optionControl">
                                        <label class="switch_checkbox_item">
                                            <input type="checkbox" v-model="option.soldoutToggle">
                                            <div class="switch_checkbox"><span></span></div>
                                        </label>
                                        <div class="delete-icon" @click="deleteOption(item.id, option.id)"><inline-svg :src="require('@/assets/img/delete_icon.svg')"/></div>
                                    </div>
                                </div>
                                <div class="btn brdr_btn" @click="addNewOption(item.id)">Add new option</div>
                            </div>
                        </div>
                        <div class="btn brdr_btn" @click="addNewVariant">Add new variant</div>
                    </div>
                </div>
                <div class="brdr_content_wrpr">
                    <h3 class="brdr_content_title">Automations</h3>
                    <div class="txt-wrap mb-15">
                        <p>
                            Trigger any action with our 3rd party integrations when the product is purchased, refunded, subscribed to, or canceled.
                        </p>
                    </div>
                    <div class="btn brdr_btn" @click="showAutomationPopup">Create new automation</div>
                </div>
            </div>                   

            <div class="bottom_btns_wrpr">
                <div class="left">
                    <a href="#" class="btn brdr_btn">Cancel</a>
                    <a href="#" class="btn">Save changes</a>
                </div>
                <div class="btn brdr_btn red_brdr_btn ml_a" @click="deleteProduct(currentProduct.id)">Delete Product</div>
            </div>
        </div>
        <div class="popup_right_side">
            <h3 class="popup_title">App preview</h3>
            <p>The app will look something like this in your funnel</p>
            <div class="custom_video_player">
                <img src="@/assets/img/video_player_overlay.jpg" alt="" class="video_player_overlay">
                <a href="" class="play_btn"><inline-svg :src="require('@/assets/img/play_icon.svg')"/></a>
            </div>
        </div>
    </div>
    
</template>

<script>
import VSwatches from 'vue-swatches'

import 'vue-swatches/dist/vue-swatches.css'

export default {
    name: "ProductSettingsPopup",
    props: {
        currentProduct: {
            require: true,
            type: Object
        },
        delete: {
            require: true,
            type: Function
        }
    },
    components: {
        VSwatches
    },
    data() {
        return {
            color: "#68C2E9",
            swatches: ['#FB595B', '#68C2E9', '#15D7AE', '#FDCC5E', '#4368E0', '#252A32', '#636A7B', '#C5C7D2', '#2E408C', '#97AACD', '#449CF4', '#6689FC'],
            variants: [
                {
                    id: 1,
                    variantControl: "size",
                    options: []
                }
            ],
            showRightPanel: false,
            settingsToggle: true,
            recurringTimes: {
                selectValue: '4',
                selectOptions: ["4", "5", "6", "7"],
            },
            billingCycle: {
                selectValue: '4',
                selectOptions: ["4", "5", "6", "7"],
            },
            cycleType: {
                selectValue: 'day(s)',
                selectOptions: ["day(s)", "day(s)", "day(s)", "day(s)"],
            }
        }
    },
    methods: {
        showAutomationPopup() {
            this.$store.commit("showAutomationPopup")
        },
        closePopup() {
            this.$store.commit("closeProductSettingsPopup")
        },
        addNewVariant() {
            this.variants.push({
                id: new Date().getTime(),
                variantControl: "",
                options: []
            })
        },
        deleteVariant(id) {
            this.variants = this.variants.filter((item) => item.id !== id)
        },
        addNewOption(id) {
            const idx = this.variants.findIndex((item) => item.id === id)
            this.variants[idx].options.push({
                id: new Date().getTime(),
                optionControl: "",
                soldoutToggle: true
            })
        },
        deleteOption(variantId, optionId) {
            this.variants = this.variants.map((item) => {
                if(item.id === variantId) {
                    item.options = item.options.filter(option => option.id !== optionId)
                }
                return item
            })
            
        },
        deleteProduct(id) {
            this.$emit("delete", id)
        }
    }
}
</script>