<template>
    <div>
        <div class="atn-trigger-items">
            <div class="item" @click="selectTrigger(item.id)" :class="{active: item.active}" v-for="item in getTriggerItems" :key="item.id">
                <div class="icon"><img :src="item.icon" alt=""></div>
                <span>{{item.text}}</span>
            </div>
        </div>
    </div>
</template>

<script>
import {mapGetters} from "vuex"
export default {
    name: "Step1",
    data() {
        return {
            triggerItems: [
                {
                    id: 1,
                    icon: require('@/assets/img/tg-icon-1.svg'),
                    text: "On Purchase",
                    active: true 
                },
                {
                    id: 2,
                    icon: require('@/assets/img/tg-icon-2.svg'),
                    text: "On Purchase",
                    active: false
                },
                {
                    id: 3,
                    icon: require('@/assets/img/tg-icon-3.svg'),
                    text: "On Purchase",
                    active: false
                },
                {
                    id: 4,
                    icon: require('@/assets/img/tg-icon-4.svg'),
                    text: "On Purchase",
                    active: false
                }
            ]
        }
    },
    computed: {
        ...mapGetters(["getTriggerItems"])
    },
    methods: {
        selectTrigger(id) {
            this.$store.commit("selectTrigger", id)
        }
    }
}
</script>