<template>
    <div class="widgets" :class="addClass">
        <div v-for="item in getStatData" class="stat-widget" :key="item.id">
            <img :src="item.imgPath" class="widget-icon">
            <span class="stat-title">{{item.title}}</span>
            <div class="stat-info">
                <div class="small-text">{{item.value}}</div>
                <div class="delta" :class="item.deltaClass">{{item.delta}}</div>
            </div>
        </div>
    </div>
</template>

<script>

import {mapGetters} from "vuex"

export default {
    name: "Statistic",
    props: {
        addClass: String
    },
    computed: {
        ...mapGetters(["getStatData"])
    }
}
</script>